{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a spatial optimization and pattern matching task. The core difficulty lies in determining the optimal sequence of queries to identify the exact translation/rotation of known shapes within a grid while minimizing cost.",
  "helpers": [
    {
      "label": "pattern_matching_and_uncertainty",
      "instructions": "Given a set of known polyomino shapes and a grid containing noisy aggregate query results, identify all possible valid placements (translations and rotations) of each polyomino that are consistent with the observed data. For each placement, calculate the probability of correctness based on the noise level of the queries."
    },
    {
      "label": "probing_strategy_optimization",
      "instructions": "Develop a decision-making algorithm that selects the next optimal probe (drilling or aggregate query) by evaluating the expected reduction in uncertainty (information gain) versus the cost of the probe. The goal is to find a sequence of actions that minimizes the total cost required to reach a confidence threshold for all suspected oil-containing cells."
    }
  ],
  "synthesis_brief": "Combine the list of probable polyomino placements with the optimized probing sequence to determine the final set of oil-containing cells and the total cost incurred. Verify that the final guess is consistent with all query results and that the cost is minimized according to the decision logic."
}

